module counter10bit_up (
    input clk,
    input rst,
    input en,
    output [9:0] q
);

    reg [9:0] count_reg;

    always @(posedge clk or posedge rst) begin
        if (rst)
            count_reg <= 10'b0000000000;
        else if (en)
            count_reg <= count_reg + 1;
    end

    assign q = count_reg;

endmodule
